import torch
import mindspore as ms
import numpy as np
from mindspore import mint
from mindspore.nn import Cell
from mindspore.common import Tensor
from mindspore.common import dtype as mstype
from mindspore.common.dtype import _dtype_to_nptype
from ...grad import GradOfAllInputs
from ...meta import OpsFactory
from ...utils import allclose_nparray
from ...utils import wrap_op


@wrap_op
class Atan2(Cell):
    def __init__(self):
        super().__init__()
        self.op = mint.atan2

    def construct(self, input_x, other):
        out = self.op(input_x, other)
        return out


class Atan2Module(torch.nn.Module):
    def __init__(self):
        super().__init__()
        self.torch_atan2 = torch.atan2

    def forward(self, input_x, other):
        out = self.torch_atan2(input_x, other)
        return out


class Atan2Mock(OpsFactory):
    def __init__(self, inputs=None, grads=None):
        if isinstance(inputs[0], Tensor):
            self.ms_type = inputs[0].dtype
        elif isinstance(inputs[1], Tensor):
            self.ms_type = inputs[1].dtype
        else:
            self.ms_type = mstype.float32

        super().__init__(dtype=_dtype_to_nptype(self.ms_type))

        self.input_x = inputs[0]
        if isinstance(self.input_x, Tensor):

            if self.ms_type == ms.bfloat16:
                self.input_x_np = inputs[0].float().asnumpy()
                self.loss = 0.02
            else:
                self.input_x_np = inputs[0].asnumpy()
        else:
            self.input_x_np = np.array(inputs[0])

        self.other = inputs[1]
        if isinstance(self.other, Tensor):
            if self.ms_type == ms.bfloat16:
                self.other_np = inputs[1].float().asnumpy()
                self.loss = 0.02
            else:
                self.other_np = inputs[1].asnumpy()
        else:
            self.other_np = np.array(inputs[1])

        if grads is None or len(grads) == 0:
            self.out_grad_np = None

    def forward_mindspore_impl(self):
        net = Atan2()
        out = net(self.input_x, self.other)
        if isinstance(out, (int, float)):
            return np.array(out)
        if out.dtype == ms.bfloat16:
            assert out.dtype == ms.bfloat16
            return out.float().asnumpy()
        return out.asnumpy()

    def grad_mindspore_impl(self):
        if self.out_grad_np is None:
            out = self.forward_mindspore_impl()
            sens = np.random.randn(*list(out.shape))
            self.out_grad_np = np.array(sens, dtype=out.dtype)
        net = Atan2()
        if self.ms_type == ms.bfloat16:
            out_grad_ms = Tensor(self.out_grad_np, ms.bfloat16)
            self.out_grad_np = out_grad_ms.float().asnumpy()
        else:
            out_grad_ms = Tensor(self.out_grad_np)
        grad_net = GradOfAllInputs(net)
        grad_net.set_train()
        grad = grad_net(self.input_x, self.other, out_grad_ms)
        if grad[0].dtype == ms.bfloat16:
            return grad[0].float().asnumpy(), grad[1].float().asnumpy()
        return grad[0].asnumpy(), grad[1].asnumpy()

